import React, { useState, useEffect } from 'react';
import { getEnhancementModes, enhanceSlides } from '../services/api';

export default function AIEnhancer({ markdown, onEnhanced, disabled }) {
  const [modes, setModes] = useState([]);
  const [selectedMode, setSelectedMode] = useState('polish');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    getEnhancementModes()
      .then(setModes)
      .catch(() => setModes([{ key: 'polish', label: 'Polish' }, { key: 'expand', label: 'Expand' }, { key: 'summarize', label: 'Summarize' }]));
  }, []);

  async function handleEnhance() {
    if (!markdown.trim()) return;
    setLoading(true);
    setError('');
    try {
      const result = await enhanceSlides(markdown, selectedMode);
      onEnhanced(result.markdown, result.slides);
    } catch (err) {
      const msg = err.response?.data?.error || 'AI enhancement failed. Please try again.';
      setError(msg);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="card ai-enhancer">
      <div className="card-header">
        <h2 className="card-title">AI Enhancement</h2>
        <span className="beta-badge">OpenAI</span>
      </div>

      <p className="ai-description">
        Use AI to automatically improve your slide content. Choose an enhancement mode below.
      </p>

      <div className="mode-selector">
        {modes.map((m) => (
          <button
            key={m.key}
            className={`mode-chip ${selectedMode === m.key ? 'active' : ''}`}
            onClick={() => setSelectedMode(m.key)}
            disabled={loading || disabled}
          >
            {m.label}
          </button>
        ))}
      </div>

      {error && <p className="error-msg">{error}</p>}

      <button
        className="btn btn-primary btn-full"
        onClick={handleEnhance}
        disabled={loading || disabled || !markdown.trim()}
      >
        {loading ? 'Enhancing with AI…' : `Enhance: ${modes.find(m => m.key === selectedMode)?.label || selectedMode}`}
      </button>

      {disabled && (
        <p className="hint">Parse your slides first to enable AI enhancement.</p>
      )}
    </div>
  );
}
